export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;

    // CORS headers for public access
    const corsHeaders = {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, PUT, DELETE, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    };

    if (request.method === 'OPTIONS') {
      return new Response(null, { status: 204, headers: corsHeaders });
    }

    try {
      // Request ID for tracing across services
      const requestId = crypto.randomUUID();
      const enrichedHeaders = new Headers(request.headers);
      enrichedHeaders.set('X-Request-ID', requestId);
      enrichedHeaders.set('X-Gateway-Timestamp', Date.now().toString());

      // Route to appropriate internal service
      let response;

      if (path.startsWith('/api/users')) {
        response = await routeToService(env.USER_SERVICE, request, enrichedHeaders, '/api/users');
      } else if (path.startsWith('/api/orders')) {
        response = await routeToService(env.ORDER_SERVICE, request, enrichedHeaders, '/api/orders');
      } else if (path.startsWith('/api/notifications')) {
        response = await routeToService(env.NOTIFICATION_SERVICE, request, enrichedHeaders, '/api/notifications');
      } else if (path.startsWith('/api/auth')) {
        response = await routeToService(env.AUTH_SERVICE, request, enrichedHeaders, '/api/auth');
      } else if (path === '/health') {
        response = await healthCheck(env);
      } else {
        response = new Response(JSON.stringify({
          error: 'Not Found',
          message: `No service registered for path: ${path}`,
          availableRoutes: ['/api/users', '/api/orders', '/api/notifications', '/api/auth', '/health']
        }), {
          status: 404,
          headers: { 'Content-Type': 'application/json' }
        });
      }

      // Attach CORS and tracing headers to response
      const newHeaders = new Headers(response.headers);
      Object.entries(corsHeaders).forEach(([key, value]) => newHeaders.set(key, value));
      newHeaders.set('X-Request-ID', requestId);
      newHeaders.set('X-Served-By', 'edge-gateway');

      return new Response(response.body, {
        status: response.status,
        statusText: response.statusText,
        headers: newHeaders,
      });

    } catch (err) {
      return new Response(JSON.stringify({
        error: 'Gateway Error',
        message: err.message,
      }), {
        status: 502,
        headers: { 'Content-Type': 'application/json', ...corsHeaders },
      });
    }
  }
};

async function routeToService(serviceBinding, originalRequest, enrichedHeaders, basePath) {
  if (!serviceBinding) {
    return new Response(JSON.stringify({
      error: 'Service Unavailable',
      message: `Service binding not configured for ${basePath}`
    }), {
      status: 503,
      headers: { 'Content-Type': 'application/json' }
    });
  }

  const url = new URL(originalRequest.url);
  // Preserve the full path and query string
  const serviceUrl = new URL(url.pathname + url.search, 'http://internal-service');

  const serviceRequest = new Request(serviceUrl.toString(), {
    method: originalRequest.method,
    headers: enrichedHeaders,
    body: originalRequest.body,
  });

  return serviceBinding.fetch(serviceRequest);
}

async function healthCheck(env) {
  const services = {
    USER_SERVICE: env.USER_SERVICE,
    ORDER_SERVICE: env.ORDER_SERVICE,
    NOTIFICATION_SERVICE: env.NOTIFICATION_SERVICE,
    AUTH_SERVICE: env.AUTH_SERVICE,
  };

  const checks = {};

  for (const [name, binding] of Object.entries(services)) {
    try {
      if (!binding) {
        checks[name] = { status: 'not_configured' };
        continue;
      }
      const start = Date.now();
      const res = await binding.fetch(new Request('http://internal-service/health'));
      const latency = Date.now() - start;
      const body = await res.json();
      checks[name] = { status: 'healthy', latency_ms: latency, details: body };
    } catch (err) {
      checks[name] = { status: 'unhealthy', error: err.message };
    }
  }

  const allHealthy = Object.values(checks).every(
    c => c.status === 'healthy' || c.status === 'not_configured'
  );

  return new Response(JSON.stringify({
    status: allHealthy ? 'healthy' : 'degraded',
    timestamp: new Date().toISOString(),
    services: checks,
  }), {
    status: allHealthy ? 200 : 503,
    headers: { 'Content-Type': 'application/json' },
  });
}


