export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const requestId = request.headers.get('X-Request-ID') || 'unknown';

    // Simple router
    if (path === '/health') {
      return jsonResponse({ service: 'auth-service', status: 'healthy', requestId });
    }

    if (path === '/api/auth/login' && method === 'POST') {
      return handleLogin(request, env, requestId);
    }

    if (path === '/api/auth/verify' && method === 'POST') {
      return handleVerify(request, env, requestId);
    }

    if (path === '/api/auth/refresh' && method === 'POST') {
      return handleRefresh(request, env, requestId);
    }

    return jsonResponse({ error: 'Not Found', requestId }, 404);
  }
};

async function handleLogin(request, env, requestId) {
  try {
    const { email, password } = await request.json();

    if (!email || !password) {
      return jsonResponse({ error: 'Email and password required', requestId }, 400);
    }

    // Simulate authentication (in production, check against KV/D1/external DB)
    // Using KV to store/retrieve user credentials
    const storedUser = env.AUTH_KV ? await env.AUTH_KV.get(`user:${email}`, 'json') : null;

    if (storedUser && storedUser.password === await hashPassword(password)) {
      const token = await generateToken({ userId: storedUser.id, email }, env);
      const refreshToken = await generateToken({ userId: storedUser.id, type: 'refresh' }, env, '7d');

      return jsonResponse({
        success: true,
        token,
        refreshToken,
        user: { id: storedUser.id, email: storedUser.email, name: storedUser.name },
        requestId,
      });
    }

    // Demo mode - return a mock token if no KV configured
    if (!env.AUTH_KV) {
      const mockToken = btoa(JSON.stringify({ userId: 'demo-user', email, exp: Date.now() + 3600000 }));
      return jsonResponse({
        success: true,
        token: mockToken,
        refreshToken: 'demo-refresh-token',
        user: { id: 'demo-user', email, name: 'Demo User' },
        requestId,
        _note: 'Demo mode - no AUTH_KV configured',
      });
    }

    return jsonResponse({ error: 'Invalid credentials', requestId }, 401);
  } catch (err) {
    return jsonResponse({ error: 'Login failed', message: err.message, requestId }, 500);
  }
}

async function handleVerify(request, env, requestId) {
  try {
    const { token } = await request.json();
    if (!token) {
      return jsonResponse({ error: 'Token required', requestId }, 400);
    }

    const decoded = JSON.parse(atob(token));
    if (decoded.exp && decoded.exp < Date.now()) {
      return jsonResponse({ valid: false, error: 'Token expired', requestId }, 401);
    }

    return jsonResponse({ valid: true, user: decoded, requestId });
  } catch (err) {
    return jsonResponse({ valid: false, error: 'Invalid token', requestId }, 401);
  }
}

async function handleRefresh(request, env, requestId) {
  try {
    const { refreshToken } = await request.json();
    if (!refreshToken) {
      return jsonResponse({ error: 'Refresh token required', requestId }, 400);
    }

    // In production, validate refresh token against stored tokens
    const newToken = btoa(JSON.stringify({ userId: 'refreshed-user', exp: Date.now() + 3600000 }));
    return jsonResponse({ success: true, token: newToken, requestId });
  } catch (err) {
    return jsonResponse({ error: 'Refresh failed', message: err.message, requestId }, 500);
  }
}

async function hashPassword(password) {
  const encoder = new TextEncoder();
  const data = encoder.encode(password);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(hash)));
}

async function generateToken(payload, env, expiry = '1h') {
  const exp = expiry === '7d' ? Date.now() + 604800000 : Date.now() + 3600000;
  return btoa(JSON.stringify({ ...payload, exp, iat: Date.now() }));
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      'X-Service': 'auth-service',
    },
  });
}


