export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);
    const path = url.pathname;
    const method = request.method;
    const requestId = request.headers.get('X-Request-ID') || 'unknown';

    // Authenticate internal requests (optional - can trust service bindings)
    const authResult = await authenticateRequest(request, env);

    if (path === '/health') {
      return jsonResponse({ service: 'user-service', status: 'healthy', requestId });
    }

    // Route handling
    if (path === '/api/users' && method === 'GET') {
      return listUsers(env, url, requestId);
    }

    if (path === '/api/users' && method === 'POST') {
      return createUser(request, env, requestId);
    }

    const userIdMatch = path.match(/^\/api\/users\/([^/]+)$/);
    if (userIdMatch) {
      const userId = userIdMatch[1];
      if (method === 'GET') return getUser(userId, env, requestId);
      if (method === 'PUT') return updateUser(userId, request, env, requestId);
      if (method === 'DELETE') return deleteUser(userId, env, requestId);
    }

    if (path.match(/^\/api\/users\/([^/]+)\/profile$/) && method === 'GET') {
      const userId = path.match(/^\/api\/users\/([^/]+)\/profile$/)[1];
      return getUserProfile(userId, env, requestId);
    }

    return jsonResponse({ error: 'Not Found', requestId }, 404);
  }
};

async function authenticateRequest(request, env) {
  // If request comes from service binding, we can optionally verify
  // the X-Gateway-Timestamp to ensure freshness
  const gatewayTimestamp = request.headers.get('X-Gateway-Timestamp');
  if (gatewayTimestamp) {
    const age = Date.now() - parseInt(gatewayTimestamp);
    if (age > 30000) {
      // Request older than 30 seconds - might be replay
      return { valid: false, reason: 'stale_request' };
    }
  }

  // For inter-service calls, optionally verify auth token
  const authHeader = request.headers.get('Authorization');
  if (authHeader && env.AUTH_SERVICE) {
    const token = authHeader.replace('Bearer ', '');
    try {
      const authResponse = await env.AUTH_SERVICE.fetch(
        new Request('http://internal-service/api/auth/verify', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ token }),
        })
      );
      return authResponse.json();
    } catch {
      return { valid: false, reason: 'auth_service_unavailable' };
    }
  }

  return { valid: true, reason: 'internal_service_binding' };
}

async function listUsers(env, url, requestId) {
  const page = parseInt(url.searchParams.get('page') || '1');
  const limit = parseInt(url.searchParams.get('limit') || '10');
  const search = url.searchParams.get('search') || '';

  // Using KV for user storage (D1 would be better for production)
  if (env.USER_KV) {
    const listResult = await env.USER_KV.list({ prefix: 'user:', limit: 1000 });
    let users = [];

    for (const key of listResult.keys) {
      const user = await env.USER_KV.get(key.name, 'json');
      if (user) {
        if (search && !user.name?.toLowerCase().includes(search.toLowerCase()) &&
            !user.email?.toLowerCase().includes(search.toLowerCase())) {
          continue;
        }
        users.push({ ...user, password: undefined });
      }
    }

    const total = users.length;
    const start = (page - 1) * limit;
    users = users.slice(start, start + limit);

    return jsonResponse({
      users,
      pagination: { page, limit, total, totalPages: Math.ceil(total / limit) },
      requestId,
    });
  }

  // Demo data
  return jsonResponse({
    users: [
      { id: '1', name: 'Alice Johnson', email: 'alice@example.com', role: 'admin' },
      { id: '2', name: 'Bob Smith', email: 'bob@example.com', role: 'user' },
      { id: '3', name: 'Charlie Brown', email: 'charlie@example.com', role: 'user' },
    ],
    pagination: { page: 1, limit: 10, total: 3, totalPages: 1 },
    requestId,
    _note: 'Demo data - no USER_KV configured',
  });
}

async function getUser(userId, env, requestId) {
  if (env.USER_KV) {
    const user = await env.USER_KV.get(`user:${userId}`, 'json');
    if (!user) {
      return jsonResponse({ error: 'User not found', requestId }, 404);
    }
    return jsonResponse({ user: { ...user, password: undefined }, requestId });
  }

  return jsonResponse({
    user: { id: userId, name: 'Demo User', email: 'demo@example.com', role: 'user' },
    requestId,
  });
}

async function createUser(request, env, requestId) {
  try {
    const body = await request.json();
    const { name, email, role } = body;

    if (!name || !email) {
      return jsonResponse({ error: 'Name and email are required', requestId }, 400);
    }

    const user = {
      id: crypto.randomUUID(),
      name,
      email,
      role: role || 'user',
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    if (env.USER_KV) {
      await env.USER_KV.put(`user:${user.id}`, JSON.stringify(user));
      await env.USER_KV.put(`user-email:${email}`, user.id);
    }

    // Notify notification service about new user
    if (env.NOTIFICATION_SERVICE) {
      ctx?.waitUntil?.(
        env.NOTIFICATION_SERVICE.fetch(
          new Request('http://internal-service/api/notifications/send', {
            method: 'POST',
            headers: {
              'Content-Type': 'application/json',
              'X-Request-ID': requestId,
            },
            body: JSON.stringify({
              type: 'user_created',
              recipient: email,
              data: { name, userId: user.id },
            }),
          })
        ).catch(() => {})
      );
    }

    return jsonResponse({ user, requestId }, 201);
  } catch (err) {
    return jsonResponse({ error: 'Failed to create user', message: err.message, requestId }, 500);
  }
}

async function updateUser(userId, request, env, requestId) {
  try {
    const body = await request.json();

    if (env.USER_KV) {
      const existing = await env.USER_KV.get(`user:${userId}`, 'json');
      if (!existing) {
        return jsonResponse({ error: 'User not found', requestId }, 404);
      }

      const updated = {
        ...existing,
        ...body,
        id: userId,
        updatedAt: new Date().toISOString(),
      };

      await env.USER_KV.put(`user:${userId}`, JSON.stringify(updated));
      return jsonResponse({ user: { ...updated, password: undefined }, requestId });
    }

    return jsonResponse({
      user: { id: userId, ...body, updatedAt: new Date().toISOString() },
      requestId,
    });
  } catch (err) {
    return jsonResponse({ error: 'Failed to update user', message: err.message, requestId }, 500);
  }
}

async function deleteUser(userId, env, requestId) {
  if (env.USER_KV) {
    const existing = await env.USER_KV.get(`user:${userId}`, 'json');
    if (!existing) {
      return jsonResponse({ error: 'User not found', requestId }, 404);
    }
    await env.USER_KV.delete(`user:${userId}`);
    if (existing.email) {
      await env.USER_KV.delete(`user-email:${existing.email}`);
    }
  }

  return jsonResponse({ success: true, message: 'User deleted', requestId });
}

async function getUserProfile(userId, env, requestId) {
  const userResponse = await getUser(userId, env, requestId);
  const userData = await userResponse.json();

  // Enrich with order data if order service is available
  let recentOrders = [];
  if (env.ORDER_SERVICE) {
    try {
      const orderResponse = await env.ORDER_SERVICE.fetch(
        new Request(`http://internal-service/api/orders?userId=${userId}&limit=5`, {
          headers: { 'X-Request-ID': requestId },
        })
      );
      const orderData = await orderResponse.json();
      recentOrders = orderData.orders || [];
    } catch {
      recentOrders = [];
    }
  }

  return jsonResponse({
    profile: {
      ...userData.user,
      recentOrders,
    },
    requestId,
  });
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      'X-Service': 'user-service',
    },
  });
}


